```class Solution {
public:
    int countGoodIntegers(int n, int k) {
        int result = 0;
        for (int i = 1; i <= n; i++) {
            int num = i * (i + 1) / 2;
            int digits = num / 10;
            int remainder = num % 10;
            if (digits == k && remainder == 0) {
                result++;
            }
        }
        return result;
    }
};
